namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

inline auto create_table_as_select() {
  const auto select_from = sqlgen::SelectFrom<Source>{
      .where = sqlgen::columns<Source>().value > 100,
      .fields = {sqlgen::columns<Source>().value}};

  const auto create_as = sqlgen::create_as<Target>(select_from);

  return sqlgen::to_sql(create_as);
}

